UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Triticale, Wintergerst, Winterrogge, Wintertarwe, Zomergerst, Zomertarwe", "doelorganisme": "Nerfamarant, Papegaaienkruid, Zandraket, Spiesmelde, Veerdelig tandzaad, Herderstasje, Kleine veldkers, Veldkers, Kluwen hoornbloem, Melganzenvoet, Stippelganzenvoet, Zeegroene ganzenvoet, Gele ganzenbloem, Kleine varkenskers, Grote varkenskers, Kroontjeskruid, Gewone steenraket, Gewone duivenkervel, Bleekgele hennepnetel, Harig knopkruid, Kaal knopkruid, Kleine ooievaarsbek, Hoenderbeet, Echte kamille, Reukloze kamille, Schijfkamille, Tuinbingelkruid, Akkervergeet-mij-nietje, Varkensgras, Zwaluwtong, Waterpeper, Knopige duizendknoop, Perzikkruid, Viltige duizendknoop, Akkerboterbloem, Blaartrekkende boterbloem, Gewone melkdistel, Gewone spurrie, Vogelpootklaver, Akkerereprijs, Klimopereprijs, Vierzaadwikke", "locatie": "Onbedekt", "toepassingsmethode": "Na opkomst ", "dosering": "0.75 L/ha", "maxToepassingen": 1, "veiligheidstermijn": "60 dagen", "opmerkingen": ["Verlaging van de dosis is toegestaan, hierbij dient rekening gehouden te worden met resistentiemanagement. Van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen."], "wCodes": ["W1"], "bbchVan": "30", "bbchTot": "45", "seizoenVan": 3, "seizoenTot": 6, "spuitvolumeMin": 150, "spuitvolumeMax": 400, "phiDagen": 60}, {"gewas": "Engels raaigras, Frans raaigras, Gekruist raaigras, Italiaans raaigras, Westerwolds raaigras, Overige raaigrassen, Hardzwenkgras, Rietzwenkgras, Roodzwenkgras, Overige zwenkgrassen, Beemdlangbloem, Bosbeemdgras, Moerasbeemdgras, Veldbeemd, Overige beemdgrassen, Fakkelgras, Kamgras, Kropaar, Ruwe smele, Struisgras, Timothee, Overige graszaadgewassen", "doelorganisme": "Nerfamarant, Papegaaienkruid, Zandraket, Spiesmelde, Veerdelig tandzaad, Herderstasje, Kleine veldkers, Veldkers, Kluwen hoornbloem, Melganzenvoet, Stippelganzenvoet, Zeegroene ganzenvoet, Gele ganzenbloem, Kleine varkenskers, Grote varkenskers, Kroontjeskruid, Gewone steenraket, Gewone duivenkervel, Bleekgele hennepnetel, Harig knopkruid, Kaal knopkruid, Kleine ooievaarsbek, Hoenderbeet, Echte kamille, Reukloze kamille, Schijfkamille, Tuinbingelkruid, Akkervergeet-mij-nietje, Varkensgras, Zwaluwtong, Waterpeper, Knopige duizendknoop, Perzikkruid, Viltige duizendknoop, Akkerboterbloem, Blaartrekkende boterbloem, Gewone melkdistel, Gewone spurrie, Vogelpootklaver, Akkerereprijs, Klimopereprijs, Vierzaadwikke", "locatie": "Onbedekt", "toepassingsmethode": "Na opkomst ", "dosering": "0.75 L/ha", "maxToepassingen": 1, "opmerkingen": ["* Verlaging van de dosering is toegestaan, hierbij dient rekening gehouden te worden met resistentiemanagement. Van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen.\nSchudden voor gebruik\nOm in het water levende organismen te beschermen is toepassing van dit middel op percelen die grenzen aan oppervlaktewater uitsluitend toegestaan indien op het gehele perceel gebruik wordt gemaakt van een techniek uit tenminste de klasse DRT95.\nVervanggewassen \nLet op: Bij her inzaai na het mislukken van de teelt kan zomertarwe worden verbouwd tenminste 1 maand en maïs worden verbouwd tenminste 2 maanden na toepassing van het middel.\nVolggewassen \nLet op: Er zijn geen beperkingen van volggewassen. Kerende grondbewerking wordt aanbevolen voordat peulvruchten worden ingezaaid.\nResistentiemanagement \nDit middel bevat de werkzame stoffen florasulam en halauxifen-methyl. florasulam behoort tot de triazolopyrimidines. De HRAC code is B. Halauxifen-methyl behoort tot de arylpicolinaten. De Hrac code is O. In Nederland zijn onkruiden aangetroffen die resistent zijn tegen werkzame stoffen met HRAC \ncode B. Omdat er binnen deze groep kruisresistentie bestaat, dit middel afwisselen met middelen met een ander werkingsmechanisme. In het kader van resistentiemanagement dient u de adviezen die gegeven worden in de voorlichtingsboodschappen, op te volgen.\n\n"], "wCodes": ["W1"], "bbchVan": "13", "bbchTot": "45", "seizoenVan": 1, "seizoenTot": 6, "spuitvolumeMin": 150, "spuitvolumeMax": 400, "maxDoseringPerSeizoen": "0.75 L/ha"}, {"gewas": "Maaigrasland, Weiland, Graszodenteelt", "doelorganisme": "Nerfamarant, Papegaaienkruid, Zandraket, Spiesmelde, Veerdelig tandzaad, Herderstasje, Kleine veldkers, Veldkers, Kluwen hoornbloem, Melganzenvoet, Stippelganzenvoet, Zeegroene ganzenvoet, Gele ganzenbloem, Kleine varkenskers, Grote varkenskers, Kroontjeskruid, Gewone steenraket, Gewone duivenkervel, Bleekgele hennepnetel, Harig knopkruid, Kaal knopkruid, Kleine ooievaarsbek, Hoenderbeet, Echte kamille, Reukloze kamille, Schijfkamille, Tuinbingelkruid, Akkervergeet-mij-nietje, Varkensgras, Zwaluwtong, Waterpeper, Knopige duizendknoop, Perzikkruid, Viltige duizendknoop, Akkerboterbloem, Blaartrekkende boterbloem, Gewone melkdistel, Gewone spurrie, Vogelpootklaver, Akkerereprijs, Klimopereprijs, Vierzaadwikke", "locatie": "Onbedekt", "toepassingsmethode": "Na opkomst ", "dosering": "0.75 L/ha", "maxToepassingen": 1, "opmerkingen": ["7 dagen voor beweiden of maaien\n* Verlaging van de dosering is toegestaan, hierbij dient rekening gehouden te worden met resistentiemanagement. Van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen.\n\nSchudden voor gebruik\nOm in het water levende organismen te beschermen is toepassing van dit middel op percelen die grenzen aan oppervlaktewater uitsluitend toegestaan indien op het gehele perceel gebruik wordt gemaakt van een techniek uit tenminste de klasse DRT95.\nVervanggewassen \nLet op: Bij her inzaai na het mislukken van de teelt kan zomertarwe worden verbouwd tenminste 1 maand en maïs worden verbouwd tenminste 2 maanden na toepassing van het middel.\nVolggewassen \nLet op: Er zijn geen beperkingen van volggewassen. Kerende grondbewerking wordt aanbevolen voordat peulvruchten worden ingezaaid.\nResistentiemanagement \nDit middel bevat de werkzame stoffen florasulam en halauxifen-methyl. florasulam behoort tot de triazolopyrimidines. De HRAC code is B. Halauxifen-methyl behoort tot de arylpicolinaten. De Hrac code is O. In Nederland zijn onkruiden aangetroffen die resistent zijn tegen werkzame stoffen met HRAC \ncode B. Omdat er binnen deze groep kruisresistentie bestaat, dit middel afwisselen met middelen met een ander werkingsmechanisme. In het kader van resistentiemanagement dient u de adviezen die gegeven worden in de voorlichtingsboodschappen, op te volgen.\n\n"], "wCodes": ["W1"], "bbchVan": "13", "bbchTot": "45", "seizoenVan": 9, "seizoenTot": 6, "spuitvolumeMin": 150, "spuitvolumeMax": 400, "maxDoseringPerSeizoen": "0.75 L/ha"}]'::jsonb, last_synced_at = NOW() WHERE toelatingsnummer = '16188';
